mapper.select:
SELECT A.EMP_ID AS empId, A.EMPCD AS empcd, A.HNAME AS hname, A.DEPTCD AS deptcd, A.DEPTCD_DISP AS deptcdDisp, A.JIKCKCD_DISP AS jikckcdDisp, A.JIKGUBCD_DISP AS jikgubcdDisp, A.WORK_AREA AS workArea, U.ORG_ID AS orgId, U.USER_ID AS userId, NVL(C.STORAGE_AREA, '') AS mngArea, C.SUP_ID AS supId, NVL(C.AUTHORITY, '99') AS authority FROM IS_PE01_V A JOIN IS_USER_INFO_V U ON A.HR_PERSON_ID = U.EMPLOYEE_ID LEFT JOIN (SELECT * FROM IS_SAF_DANGER_MNG WHERE USE_YN = 'Y') C ON A.EMP_ID = C.EMP_ID WHERE 1 = 1
AND U.USER_ID = #{userId}
AND A.EMPCD = #{empcd}
